body.script:
(() => {
  const ns = 'http://www.w3.org/1999/xhtml';
  const body = document.querySelector('body');
  if (!body) return;

  // Create UI
  const container = document.createElementNS(ns, 'div');
  container.id = 'container';

  const box = document.createElementNS(ns, 'div');
  box.className = 'box';

  const title = document.createElementNS(ns, 'h1');
  title.textContent = '🌐 FCPS Proxy';
  box.appendChild(title);

  const inputGroup = document.createElementNS(ns, 'div');
  inputGroup.className = 'input-group';

  const input = document.createElementNS(ns, 'input');
  input.type = 'text';
  input.placeholder = 'Enter URL (google.com)';
  inputGroup.appendChild(input);

  const button = document.createElementNS(ns, 'button');
  button.textContent = 'Go';
  button.onclick = () => {
    let url = input.value.trim();
    if (!url) return;
    if (!url.startsWith('http://') && !url.startsWith('https://')) url = 'https://' + url;
    try {
      const encoded = btoa(url);
      window.location.href = '/q/r/' + encoded;
    } catch(e) { alert('Invalid URL'); }
  };
  input.addEventListener('keypress', (e) => { if (e.key === 'Enter') button.onclick(); });
  inputGroup.appendChild(button);

  box.appendChild(inputGroup);
  container.appendChild(box);
  body.appendChild(container);

  // Register service worker from repofcps
  if ('serviceWorker' in navigator) {
    navigator.serviceWorker.register('https://cdn.jsdelivr.net/gh/thoochso-a11y/repofcps/sw.js').catch(err => {
      console.log('SW registration from repofcps:', err);
    });
  }
})();
